export const generateSermonVisual = async (prompt: string, aspectRatio: AspectRatio, resolution: ImageResolution): Promise<string> => {
  const response = await getAi().models.generateContent({
    model: IMAGE_MODEL,
    contents: { parts: [{ text: prompt }] },
    config: {
      responseModalities: [Modality.IMAGE],
      imageConfig: { aspectRatio: aspectRatio, imageSize: resolution }
    }
  });
  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData && part.inlineData.data) return `data:image/png;base64,${part.inlineData.data}`;
  }
  throw new Error("Failed to generate image");
};

export const generateSermonVideo = async (prompt: string, aspectRatio: AspectRatio, resolution: VideoResolution): Promise<{url: string, metadata: any}> => {
  const ai = getAi();
  const supportedAspectRatio = (aspectRatio === '9:16' || aspectRatio === '16:9') ? aspectRatio : '16:9';
  let operation = await ai.models.generateVideos({
    model: VIDEO_MODEL,
    prompt: prompt,
    config: { numberOfVideos: 1, resolution: resolution, aspectRatio: supportedAspectRatio }
  });
  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 5000));
    operation = await ai.operations.getVideosOperation({operation: operation});
  }
  const videoUri = operation.response?.generatedVideos?.[0]?.video?.uri;
  const videoMetadata = operation.response?.generatedVideos?.[0]?.video;
  const response = await fetch(`${videoUri}&key=${process.env.API_KEY}`);
  const blob = await response.blob();
  return { url: URL.createObjectURL(blob), metadata: videoMetadata };
};

export const extendSermonVideo = async (previousMetadata: any, prompt: string, aspectRatio: string): Promise<{url: string, metadata: any}> => {
  const ai = getAi();
  const supportedAspectRatio = (aspectRatio === '9:16' || aspectRatio === '16:9') ? aspectRatio : '16:9';
  let operation = await ai.models.generateVideos({
    model: VIDEO_EXTEND_MODEL,
    prompt: prompt,
    video: previousMetadata,
    config: { numberOfVideos: 1, resolution: '720p', aspectRatio: supportedAspectRatio }
  });
  while (!operation.done) {
     await new Promise(resolve => setTimeout(resolve, 5000));
     operation = await ai.operations.getVideosOperation({operation: operation});
  }
  const videoUri = operation.response?.generatedVideos?.[0]?.video?.uri;
  const videoMetadata = operation.response?.generatedVideos?.[0]?.video;
  const response = await fetch(`${videoUri}&key=${process.env.API_KEY}`);
  const blob = await response.blob();
  return { url: URL.createObjectURL(blob), metadata: videoMetadata };
};

export const editSermonVisual = async (currentImageBase64: string, editInstruction: string): Promise<string> => {
  const cleanBase64 = currentImageBase64.replace(/^data:image\/(png|jpeg|jpg);base64,/, '');
  const response = await getAi().models.generateContent({
    model: EDIT_MODEL,
    contents: { parts: [{ inlineData: { mimeType: 'image/jpeg', data: cleanBase64 } }, { text: editInstruction }] },
    config: { responseModalities: [Modality.IMAGE] }
  });
  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData && part.inlineData.data) return `data:image/png;base64,${part.inlineData.data}`;
  }
  throw new Error("Failed to edit image");
};

